#[doc(hidden)]
#[cfg(feature = "async")]
pub fn load_cuda_module_from_async_context<F, R>(
    device_id: usize,
    f: F,
) -> Result<R, cuda_async::error::DeviceError>
where
    F: FnOnce(&Arc<cuda_core::CudaContext>) -> Result<R, crate::EmbeddedModuleError>,
{
    cuda_async::device_context::with_cuda_context(device_id, |ctx| f(ctx))?.map_err(|error| {
        if let crate::EmbeddedModuleError::Driver(error) = error {
            cuda_async::error::DeviceError::Driver(error)
        } else {
            cuda_async::error::DeviceError::KernelCache(error.to_string())
        }
    })
}

/// Async-context counterpart of [`crate::load_kernel_module`].
///
/// Loads a kernel module by stem name on `device_id`, using the async device
/// context map to find the underlying [`cuda_core::CudaContext`].
#[cfg(feature = "async")]
pub fn load_kernel_module_async(
    name: &str,
    device_id: usize,
) -> Result<Arc<cuda_core::CudaModule>, cuda_async::error::DeviceError> {
    cuda_async::device_context::with_cuda_context(device_id, |ctx| {
        crate::ltoir::load_kernel_module(ctx, name)
            .map_err(|error| cuda_async::error::DeviceError::KernelCache(error.to_string()))
    })?
}

// =============================================================================
// Argument Wrapper Types
// =============================================================================

/// Wrapper for scalar values that need to be passed to kernels.
///
/// This wrapper exists for documentation purposes and to make the intent clear.
/// The macro handles unwrapping these properly.
///
/// # Example
///
/// ```ignore
/// // SAFETY: args match `scale`'s signature.
/// unsafe {
///     cuda_launch! {
///         kernel: scale,
///         // ...
///         args: (Scalar(factor), &input_dev, &mut output_dev)
///     }
/// }
/// ```
pub struct Scalar<T>(pub T);

/// Wrapper indicating a device buffer is read-only in the kernel.
///
/// # Example
///
/// ```ignore
/// // SAFETY: args match `transform`'s signature.
/// unsafe {
///     cuda_launch! {
///         kernel: transform,
///         // ...
///         args: (ReadOnly(&input_dev), &mut output_dev)
///     }
/// }
/// ```
pub struct ReadOnly<'a, T>(pub &'a T);

/// Wrapper indicating a device buffer is write-only in the kernel.
///
/// This is a hint for future optimizations - currently treated same as mutable.
///
/// # Example
///
/// ```ignore
/// // SAFETY: args match `generate`'s signature.
/// unsafe {
///     cuda_launch! {
///         kernel: generate,
///         // ...
///         args: (WriteOnly(&mut output_dev),)
///     }
/// }
/// ```
pub struct WriteOnly<'a, T>(pub &'a mut T);

// =============================================================================
// Length Extraction (for slice kernels)
// =============================================================================

/// Trait for types that have a length (used to pass ptr+len to kernels).
pub trait HasLength {
    fn len(&self) -> usize;
    fn is_empty(&self) -> bool {
        self.len() == 0
    }
}

impl<T> HasLength for cuda_core::DeviceBuffer<T> {
    fn len(&self) -> usize {
        self.len()
    }
}

